import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Define buffer size based on maximum expected input length
        int bufferSize = Math.min(input.length(), 10);
        byte[] buffer = new byte[bufferSize];

        // Copy input characters to buffer
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = (byte) input.charAt(i);
        }

        System.out.println("User input successfully stored in buffer");
    }
}

### Explanation:
취약유형: Buffer Overflow
